mapper.select:
SELECT c.id AS categoryId, c.name AS categoryName, COALESCE(SUM(t.amount), 0) AS amount FROM `transaction` t JOIN category c ON c.id = t.category_id WHERE t.user_id = #{userId} AND t.`date` BETWEEN #{startDate} AND #{endDate}
AND t.type = #{type}
GROUP BY c.id, c.name ORDER BY amount DESC

SELECT
    DATE_FORMAT(t.`date`, '%Y-%m') AS month,
    COALESCE(SUM(t.amount), 0) AS amount
FROM `transaction` t
WHERE t.user_id = #{userId}
  AND t.type = #{type}
  AND t.`date` BETWEEN #{startDate} AND #{endDate}
GROUP BY month
ORDER BY month
